import{_ as t,o,c as a,a2 as c}from"./chunks/framework.BWuWLRhz.js";const h=JSON.parse('{"title":"Epic: Plugin — Accounts","description":"","frontmatter":{},"headers":[],"relativePath":"epics/plugin-accounts.md","filePath":"epics/plugin-accounts.md"}'),s={name:"epics/plugin-accounts.md"};function i(r,e,d,n,l,u){return o(),a("div",null,[...e[0]||(e[0]=[c('<h1 id="epic-plugin-—-accounts" tabindex="-1">Epic: Plugin — Accounts <a class="header-anchor" href="#epic-plugin-—-accounts" aria-label="Permalink to &quot;Epic: Plugin — Accounts&quot;">​</a></h1><blockquote><p>Per-user self-service — profile, security, preferences, data portability, activity, and account deletion.</p></blockquote><h2 id="status" tabindex="-1">Status <a class="header-anchor" href="#status" aria-label="Permalink to &quot;Status&quot;">​</a></h2><p>✅ Complete</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The Account plugin (<code>fs.sovereign.account</code>) is a <code>type: platform</code>, <code>shell: overlay</code> plugin accessible to all authenticated users. It lives in the sidebar bottom chrome as the user&#39;s avatar. The plugin has grown through several epics as new capabilities were added: the initial profile/security/preferences trio, then a Data tab for cross-plugin consent management and portability export/import, an Activity tab for the personal audit feed, MFA enrollment, and subscription management for monetized plugins.</p><h2 id="tasks" tabindex="-1">Tasks <a class="header-anchor" href="#tasks" aria-label="Permalink to &quot;Tasks&quot;">​</a></h2><h4 id="✅-14-1-—-account-plugin" tabindex="-1">✅ 14.1 — Account plugin <a class="header-anchor" href="#✅-14-1-—-account-plugin" aria-label="Permalink to &quot;✅ 14.1 — Account plugin&quot;">​</a></h4><p><strong>Goal:</strong> Per-user profile, preferences, and credential management for all authenticated users.</p><p><strong>Deliverables:</strong></p><ul><li><code>plugins/account/</code> with: <ul><li><code>manifest.json</code> — id: <code>fs.sovereign.account</code>, type: <code>platform</code>, runtime: <code>native</code>, routePrefix: <code>/account</code>, shell: <code>default</code>, icon: <code>icon.svg</code>, permissions: <code>[&quot;auth:session&quot;, &quot;db:readWrite&quot;]</code>, minPlatformVersion: <code>0.4.0</code></li><li><code>icon.svg</code> — user silhouette or similar. Note: the sidebar bottom section renders the user&#39;s avatar (or initials) for <code>fs.sovereign.account</code>, not this icon; <code>icon.svg</code> is used in the Launcher grid only.</li><li><code>app/layout.tsx</code> — three-tab sub-navigation: Profile / Security / Preferences</li><li><code>app/page.tsx</code> — redirect to <code>/account/profile</code></li><li><code>app/profile/page.tsx</code> — display name + avatar upload (ACC-01, ACC-02, ACC-03). Avatar stored on disk at <code>data/avatars/&lt;user_id&gt;</code> and served via a Next.js route; <code>avatar_url</code> written to the user record.</li><li><code>app/security/page.tsx</code> — password change with current-password confirmation (ACC-04); active sessions list with revoke (ACC-05, ACC-06)</li><li><code>app/preferences/page.tsx</code> — timezone (searchable IANA dropdown, ACC-07) + appearance toggle Light / Dark / System (ACC-08)</li><li><code>db/schema.ts</code> — <code>account_prefs</code> table: <code>user_id</code> (PK/FK), <code>tenant_id</code>, <code>timezone</code> (IANA string, default <code>UTC</code>), <code>theme</code> (<code>system</code> | <code>light</code> | <code>dark</code>, default <code>system</code>), <code>updated_at</code></li><li><code>components/AvatarUpload.tsx</code>, <code>components/SessionList.tsx</code>, <code>components/TimezoneSelect.tsx</code></li></ul></li><li>Appearance preference written to both <code>account_prefs</code> (authoritative) and a <code>sv-theme</code> cookie so the shell can apply <code>data-theme</code> on the server without a DB round-trip (prevents SSR flash — see ACC-08 open question in <code>docs/plugins/account.md</code>)</li></ul><p><strong>Dependencies:</strong> Task 0.4.02 (<code>sdk.auth</code> — session, password change via <code>better-auth</code>, sessions API)</p><p><strong>SRS reference:</strong> ACC-01–ACC-08, <code>docs/plugins/account.md</code></p><p><strong>Review checklist:</strong></p><ul><li>User can update display name; change persists on reload</li><li>Avatar upload stores file, updates <code>avatar_url</code>, and is reflected in the sidebar bottom section&#39;s avatar slot</li><li>Password change succeeds with the correct current password; rejected with wrong current password; current session is preserved after a successful change</li><li>Active sessions list shows all sessions with device hint, IP, and last-active timestamp; any session except the current one can be revoked</li><li>Timezone preference stored in <code>account_prefs</code></li><li>Appearance toggle applies <code>data-theme</code> immediately without reload; preference survives page reload via the <code>sv-theme</code> cookie</li><li><code>pnpm lint</code>, <code>pnpm format:check</code>, and <code>pnpm typecheck</code> pass</li></ul><hr><p>Subsequent tasks added Account sections as part of other epics:</p><table tabindex="0"><thead><tr><th>Task</th><th>Feature added to Account</th><th>Primary epic</th></tr></thead><tbody><tr><td>0.5.11</td><td>Data tab — active consent grants with per-grant revoke</td><td><a href="./platform-shell.html">Platform Shell</a></td></tr><tr><td>0.5.12</td><td>Security tab — Log out action for current session</td><td><a href="./users-auth.html">Users &amp; Auth</a></td></tr><tr><td>0.5.13</td><td>Activity tab — personal audit feed</td><td><a href="./activity-logs.html">Activity Logs</a></td></tr><tr><td>0.5.15</td><td>Data tab — Export and Import buttons for data portability</td><td><a href="./data-sovereignty.html">Data Sovereignty</a></td></tr><tr><td>0.5.27</td><td>Security tab — TOTP enrollment/disable, passkey add/list/remove</td><td><a href="./users-auth.html">Users &amp; Auth</a></td></tr><tr><td>0.7.1</td><td>Preferences tab — push notification opt-in</td><td><a href="./notification-center.html">Notification Center</a></td></tr><tr><td>0.8.0</td><td>New Subscriptions section — purchase, import license, manage renewals</td><td><a href="./monetization.html">Monetization</a></td></tr><tr><td>1.7</td><td>Data tab — &quot;Delete your account&quot; section</td><td><a href="./users-auth.html">Users &amp; Auth</a></td></tr></tbody></table><h2 id="related-docs" tabindex="-1">Related Docs <a class="header-anchor" href="#related-docs" aria-label="Permalink to &quot;Related Docs&quot;">​</a></h2><ul><li><a href="./../plugins/">docs/plugins/account.md</a> (plugin spec)</li><li><a href="./../plugin-development.html">plugin-development.md</a></li></ul>',20)])])}const m=t(s,[["render",i]]);export{h as __pageData,m as default};
